import json

# Get all keys from locals that contain 'query_db'
query_db_vars = [var for var in list(locals().keys()) if 'query_db' in str(var)]

result = {}
for var in query_db_vars:
    data = locals()[var]
    result[var] = {
        'type': str(type(data))
    }

    if isinstance(data, list):
        result[var]['length'] = len(data)
        if len(data) > 0:
            result[var]['sample'] = data[0]
    elif isinstance(data, str):
        result[var]['value'] = data[:100]  # First 100 chars

print('__RESULT__:')
print(json.dumps(result))

